import { tasks } from "@trigger.dev/sdk/v3";
import type { multiTenantTask } from "../src/trigger/multi_tenant";

async function main() {
  const trialId = "multi_tenant_concurrency_control__8ZxofZB";
  const taskId = `multi-tenant-task-${trialId}`;

  const runs = await Promise.all([
    tasks.trigger<typeof multiTenantTask>(taskId, { userId: "user_A", jobId: "A1" }),
    tasks.trigger<typeof multiTenantTask>(taskId, { userId: "user_A", jobId: "A2" }),
    tasks.trigger<typeof multiTenantTask>(taskId, { userId: "user_B", jobId: "B1" }),
    tasks.trigger<typeof multiTenantTask>(taskId, { userId: "user_B", jobId: "B2" }),
  ]);

  console.log(`Run IDs: ${runs.map(r => r.id).join(", ")}`);
}

main().catch(console.error);
EOF

